def validate(args, output):
    nums = args[0]
    if not isinstance(output, list):
        return False
    base = set(nums)
    seen = set()
    for sub in output:
        if not isinstance(sub, list):
            return False
        if len(set(sub)) != len(sub):
            return False
        for v in sub:
            if v not in base:
                return False
        key = tuple(sorted(sub))
        if key in seen:
            return False
        seen.add(key)
    return len(seen) == (1 << len(nums))

