function validate(args, output) {
    const nums = args[0];
    if (!Array.isArray(output)) return false;
    const base = new Set(nums);
    const seen = new Set();
    for (const sub of output) {
        if (!Array.isArray(sub)) return false;
        if (new Set(sub).size !== sub.length) return false;
        for (const v of sub) if (!base.has(v)) return false;
        const key = sub.slice().sort((a, b) => a - b).join(',');
        if (seen.has(key)) return false;
        seen.add(key);
    }
    return seen.size === (1 << nums.length);
}

